package org.apache.commons.lang3.math;

import org.junit.runner.RunWith;
import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources",
    glue = "org.apache.commons.lang3.math.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
}

package org.apache.commons.lang3.math.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import static org.junit.Assert.*;

import org.apache.commons.lang3.math.NumberUtils;

public class StepDefs {

    private String inputString;
    private Object result;

    @Given("a string {string}")
    public void a_string(String str) {
        this.inputString = str;
    }

    @Given("a string {string} \\(value that exceeds Float range but fits in Double\\)")
    public void a_string_with_description(String str) {
        this.inputString = str;
    }

    @Given("a string {string} \\(value that exceeds Double range\\)")
    public void a_string_exceeds_double_range(String str) {
        this.inputString = str;
    }

    @Given("a floating point number string that fits within Float precision")
    public void a_floating_point_number_string_that_fits_within_Float_precision() {
        this.inputString = "1.23";
    }

    @When("NumberUtils.createNumber is called with this string")
    public void numberutils_createNumber_is_called_with_this_string() {
        try {
            this.result = NumberUtils.createNumber(inputString);
        } catch (Exception e) {
            // Catch any exceptions that might occur during processing
            this.result = e;
        }
    }

    @When("NumberUtils.createNumber processes the string")
    public void numberutils_createNumber_processes_the_string() {
        try {
            this.result = NumberUtils.createNumber(inputString);
        } catch (Exception e) {
            // Catch any exceptions that might occur during processing
            this.result = e;
        }
    }

    @Then("the result should be an instance of Float")
    public void the_result_should_be_an_instance_of_Float() {
        assertNotNull("Result should not be null", result);
        assertTrue("Result should be an instance of Float", result instanceof Float);
        assertEquals(Float.valueOf(inputString), (Float)result);
    }

    @Then("the result should be an instance of Double")
    public void the_result_should_be_an_instance_of_Double() {
        assertNotNull("Result should not be null", result);
        assertTrue("Result should be an instance of Double", result instanceof Double);
        assertEquals(Double.valueOf(inputString), (Double)result);
    }

    @Then("the result should be an instance of BigDecimal")
    public void the_result_should_be_an_instance_of_BigDecimal() {
        assertNotNull("Result should not be null", result);
        assertTrue("Result should be an instance of BigDecimal", result instanceof java.math.BigDecimal);
    }

    @Then("it should not incorrectly promote to a larger type due to precision checking error")
    public void it_should_not_incorrectly_promote_to_a_larger_type_due_to_precision_checking_error() {
        assertNotNull("Result should not be null", result);

        // For the floating point case, it should remain as Float if possible
        // This tests that precision checking doesn't cause unnecessary type promotion
        if ("1.23".equals(inputString)) {
            assertTrue("For '1.23', result should be Float type to preserve intended type selection", 
                      result instanceof Float);
        }
    }
}

